sp_widget.client_script:
function ($scope, $rootScope, $timeout, spUtil, $interval, $window) {
	/* widget controller. */
	var c = this;
	$scope.data.volume = {};
	$scope.maxAllowed = 25000; //25.000 GB
	var runningIntegration = false;

	$scope.noTriggerMeasurementTB = true;
	$scope.noTriggerMeasurementGB = true;
	// $window.createScope = $scope;

	//Step Size
	//Get value that should be shown on size step when setting volume size
	$scope.getAlocationUsage = function (percentage) {	
		var size = $scope.data.volume.used_size + $scope.data.volume.size;
		if ($scope.data.step3_form.volume_size.$error.max)
			size = $scope.data.volume.total_size; 
		else if ($scope.data.step3_form.volume_size.$error.min && $scope.editVolume)
			size = $scope.data.volume.used_size + $scope.editVolume.size || 0;
		else if ($scope.data.step3_form.volume_size.$error.min)
			size = $scope.data.volume.used_size;
		if (percentage) return (size / $scope.data.volume.total_size) * 100;
		else return size;
	};

	//Step USERS (SMB Share)
	$scope.redirectCreateUser = function () {
		//window.open('?id=msp_id_page&tab=user&action=new');
		$rootScope.$broadcast("openUsersTab", "createUser");
		$("#create-volume").modal("hide");
	};

	var aux = [];
	c.selectedUsers = [];
	c.selectedUsersAux = [];

	c.changed = function () {
		var index;
		aux = $("#select-users").select2("data");
		for (var j in c.selectedUsers) {
			index = c.find(aux, "id", c.selectedUsers[j].id);
			if (!index) c.selectedUsers.splice(j, 1);
		}
		for (var k in c.selectedUsersAux) {
			index = c.find(aux, "id", c.selectedUsersAux[k]);
			if (!index) c.selectedUsersAux.splice(k, 1);
		}
		for (var l in aux) {
			index = c.find(c.selectedUsers, "id", aux[l].id);
			if (!index)
				c.selectedUsers.push({
					id: aux[l].id,
					username: aux[l].text
				});

			index = c.selectedUsersAux.indexOf(aux[l].id);
			if (index < 0) c.selectedUsersAux.push(aux[l].id);
		}
	};

	c.find = function (array, key, value) {
		for (var i in array) {
			try{
				if (array[i][key] == value) 
					return i;
			}catch(e){}
		}
		return false;
	};

	c.removeSelectedValue = function (id) {
		if (c.selectedUsersAux.indexOf(id) > -1) {
			c.selectedUsersAux.splice(c.selectedUsersAux.indexOf(id), 1);
			$("#select-users").select2("val", c.selectedUsersAux);
			c.changed();
		}
	};

	$scope.updatePermissions = function (username, permission) {
		//Get Permission Array
		var checkPermission = c.data.userPermission[permission];
		var vindex = c.find(c.data.users, "username", username);

		//Default Read
		c.data.userPermission.read[username] = true;
		c.data.users[vindex].permission = "r";

		//checkPermission[username] check add/remove

		if (
			permission == "read" ||
			(permission == "write" && !checkPermission[username])
		) {
			//Remove user permission
			c.data.users[vindex].permission = "r";
			c.data.userPermission.read[username] = true;
			c.data.userPermission.write[username] = false;
		} else {
			//Add user permission
			c.data.users[vindex].permission = "rw";
			c.data.userPermission.write[username] = true;
		}
	};
	/********** END STEP USERS (SMB Share) **********/

	/********** START Step HOSTS (NFS Share) **********/

	var auxHosts = [];
	c.selectedHosts = [];
	c.selectedHostsAux = [];

	c.hostChanged = function () {
		var index;
		auxHosts = $("#select-hosts").select2("data");
		for (var j in c.selectedHosts) {
			index = c.find(auxHosts, "id", c.selectedHosts[j].id);
			if (!index) c.selectedHosts.splice(j, 1);
		}
		for (var k in c.selectedHostsAux) {
			index = c.find(auxHosts, "id", c.selectedHostsAux[k]);
			if (!index) c.selectedHostsAux.splice(k, 1);
		}
		for (var l in auxHosts) {
			index = c.find(c.selectedHosts, "id", auxHosts[l].id);
			if (!index) {
				var vindex = c.find(c.data.hosts_list, "id", auxHosts[l].id);
				c.selectedHosts.push({
					id: auxHosts[l].id,
					display_value: auxHosts[l].text,
					ip_address: c.data.hosts_list[vindex].ip_address,
					ip_list: c.data.hosts_list[vindex].ip_list,
					iqn: c.data.hosts_list[vindex].iqn + "",
					old_iqn: c.data.hosts_list[vindex].iqn + ""
				});
			}
			index = c.selectedHostsAux.indexOf(auxHosts[l].id);
			if (index < 0) c.selectedHostsAux.push(auxHosts[l].id);
		}
	};

	c.removeHostSelectedValue = function (id) {
		if (c.selectedHostsAux.indexOf(id) > -1) {
			c.selectedHostsAux.splice(c.selectedHostsAux.indexOf(id), 1);
			$("#select-hosts").select2("val", c.selectedHostsAux);
			c.hostChanged();
		}
	};

	function getIQNHostsResult() {
		runningIntegration = true;
		$scope.server
			.get({
			action: "getIQNHostsResult",
			ms_queue_hosts_sys_id: $scope.data.ms_queue_hosts_sys_id
		})
			.then(function (response) {
			$scope.data.iqn_hosts = response.data.iqn_hosts;
			$scope.data.hosts_list = response.data.hosts_list;
			$scope.loading = false;
			runningIntegration = false;
		});
	}

	$scope.getIQNHosts = function () {
		//Save CI IQN and Run Integration
		$scope.loading = true;
		$scope.server
			.get({
			action: "getIQNHosts"
		})
			.then(function (res) {
			$scope.data.ms_queue_hosts_sys_id = res.data.ms_queue_hosts_sys_id;
			initRecordWatcher(getIQNHostsResult, "iqn_hosts");
			$scope.loading = false;
		});
	};

	function getSaveIqnResult() {
		runningIntegration = true;
		$scope.server.get({ action: "getSaveIqnResult" }).then(function (response) {
			if (response.data.result) {
				$scope.data.savedIqn = true;
				$scope.loading = false;
			}
			runningIntegration = false;
		});
	}

	$scope.saveIqn = function (sys_id, iqn) {
		//Save CI IQN and Run Integration
		$scope.loading = true;
		$scope.server
			.get({
			action: "saveIqn",
			cmdb_ci: sys_id,
			iqn: iqn
		})
			.then(function (res) {
			$scope.data.savedIqn = false;
			initRecordWatcher(getSaveIqnResult, "savedIqn");
			$scope.loading = false;
		});
	};

	$scope.saveIp = function (host_id, new_ip, new_ip_subnet, ip_id) {
		if (!new_ip || new_ip == "" || !new_ip_subnet || new_ip_subnet == "") {
			$scope.editIp[ip_id] = !$scope.editIp[ip_id];
			return;
		}
		//Save new IP
		$scope.data.errorMessage = '';
		$scope.loading = true;
		$scope.server.get({
			action: "saveIp",
			host_id: host_id,
			new_ip: new_ip,
			new_ip_subnet: new_ip_subnet,
			hosts_list: $scope.data.hosts_list
		}).then(function (res) {
			$scope.loading = false;
			if (res.data.new_ip_obj && res.data.new_ip_obj.display_value == new_ip){
				//Insert new IP in selected host list
				var host_index = c.find(c.data.hosts_list, "id", host_id);
				$scope.data.hosts_list[host_index].ip_list.push(res.data.new_ip_obj);
			}
			if (res.data.errorMessage && res.data.errorMessage != ''){
				$scope.data.errorMessage = res.data.errorMessage;
			}
		});
	};
	/********** END STEP Hosts (NFS Share) **********/	

	function loadProjectList() {
		$scope.server
			.get({
			action: "getProjects",
			volume: $scope.data.volume,
			ibx: $rootScope.selectedIbx
		})
			.then(function (response) {
			$scope.data.ms_queue_project_sys_id =
				response.data.ms_queue_project_sys_id;
			initRecordWatcher(getProjectsResult, "projects");
		});
	}

	function loadUserList() {
		$scope.server.get({
			action: "getUsers",
			volume: $scope.data.volume,
			ibx: $rootScope.selectedIbx
		}).then(function (response) {
			$scope.data.ms_queue_users_sys_id = response.data.ms_queue_users_sys_id;
			initRecordWatcher(getUsersResult, "users");
		});
	}

	function loadCustomerMetrics() {
		// Ask for CustomerMetrics list to the queue
		$scope.server
			.get({
			action: "getCustomerMetrics",
			ibx: $rootScope.selectedIbx,
			volume: $scope.data.volume
		})
			.then(function (response) {
			$scope.data.ms_queue_metrics_sys_id =
				response.data.ms_queue_metrics_sys_id;
			initRecordWatcher(getCustomerMetricsResult, "customerMetrics");
		});
	}

	$scope.redirectOnDemand = function () {
		//window.open('?id=msp_id_page&action=toggleOndemand');
		$("#create-volume").modal("hide");
		$rootScope.$broadcast("openOnDemandModal");
	};

	$scope.redirectToHostTicket = function () {
		$window.open("/msp?action=new");
	};

	$scope.switchSizeMeasurement = function (unit) {
		if ($scope.editVolume && $scope.editVolume.display_values.type == 'Block') {
			return;
		}
		$scope.data.volume.size_measurement = unit; 
		$scope.data.volume.size = 0
	};


	// Select Install type
	$scope.selectVolumeType = function (id, title) {
		//if($scope.loading)
		//return;

		$scope.data.volume.type = id;
		$scope.data.modal_title = title;

		switch ($scope.data.volume.type) {
			case "file_server_smb":
				$scope.type = "${SMB}";
				break;
			case "file_server_nfs":
				$scope.type = "${NFS}";
				break;
			case "object":
				$scope.type = "Object";
				break;
			case "block":
				$scope.type = "Block";
				break;
		}
	};

	// Watch changes on measurement and recalculate de values
	$scope.$watch("data.volume.size_measurement", function (newValue, oldValue, scope) {
		if($scope.noTriggerMeasurementTB == false){
			$scope.data.volume.size_measurement = 'tb'
			return;
		}
		if($scope.noTriggerMeasurementGB == false){
			$scope.data.volume.size_measurement = 'gb'
			return;
		}
		scope.loading = true;
		if($scope.vrCreateVolume){
			$scope.data.measurement = (newValue).toUpperCase();
		}

		scope.server.get({
			action: "changeMeasurement",
			volume: $scope.data.volume,
			from: oldValue || 'gb',
			to: newValue, 
			total_quota: $scope.data.volume.total_size,
			total_use: $scope.data.volume.used_size,
			available_size: $scope.data.volume.available_size,
			max_size: $scope.data.volume.max_size,
			max_allowed: $scope.data.volume.max_allowed

		}).then(function (res) {
			scope.data.volume = res.data.volume;
			scope.loading = false;
			$scope.maxAllowedFlag = false;
			$scope.maxAllowedFlagTB = false;
		});

	});

	$scope.verifyMaxAllowed = function(){
		$scope.maxAllowedFlagTB = false;
		$scope.maxAllowedFlag = false;
		if($scope.data.volume.size > 25 && $scope.data.measurement == "TB" ){
			$scope.maxAllowedFlagTB = true;
		}
		if ($scope.data.volume.size < 25 && $scope.data.measurement == "TB" ){
			$scope.maxAllowedFlagTB = false;
		}
		if ($scope.data.volume.size > $scope.maxAllowed && $scope.data.measurement == "GB" ){
			$scope.maxAllowedFlag = true;
		}
		if ($scope.data.volume.size < $scope.maxAllowed && $scope.data.measurement == "GB" ){
			$scope.maxAllowedFlag = false;
		}
	};

	// Watch project sys id changes
	$scope.$watch("data.volume.project.sys_id", function (newValue, oldValue, scope) {
		if (typeof newValue != "undefined" && newValue != "") {
			$scope.data.addNewProject = false;
			if($scope.data.projects){
				var project = $scope.data.projects.find(function (obj) {
					return obj.id == newValue;
				});
				scope.data.volume.project.name = project.name;
			}
		}
	});

	// Wizard Navigation
	$scope.nextStep = function () {
		/*
			STEPs MAPPING
				1: Select Volume Type
				2: Select Users
				3: Select Size
				4: Select Project
				5: Select Name
				6: Select Hosts
				7: Confirmation Screen
				8: Success Screen
		*/

		$scope.data.errorMessage = '';

		if ($scope.step < 8) {
			//Before Wizard Steps is completed
			// If NFS or Block was selected, exclude USERS step and include HOSTS step
			if (
				$scope.step + 1 == 2 &&
				($scope.data.volume.type == "file_server_nfs" ||
				 $scope.data.volume.type == "block")
			) {
				$scope.step = $scope.step + 2; //NFS and Block should skip USERs step
			} else if (
				$scope.step + 1 == 6 &&
				$scope.data.volume.type != "file_server_nfs" &&
				$scope.data.volume.type != "block"
			) {
				$scope.step = $scope.step + 2; //SMB and OBJECT should skip HOSTs step
			} else {
				$scope.step++;
			}

			//Run current step Integration
			if ($scope.step == 2) {
				loadUserList();
			} else if ($scope.step == 3) {
				loadCustomerMetrics();
			} else if ($scope.step == 4) {
				loadProjectList();
			} else if ($scope.step == 6) {
				$scope.getIQNHosts();
			}

			//Wait step loading
			if (
				$scope.step == 2 ||
				$scope.step == 3 ||
				$scope.step == 4 ||
				$scope.step == 6
			) {
				$scope.loading = true;
				$scope.loadingModal = true;

				var loadingInterval = $interval(function () {
					if (
						($scope.step == 2 && $scope.data.users && $scope.data.users != null) ||
						($scope.step == 3 && $scope.data.customerMetrics && $scope.data.customerMetrics != null) ||
						($scope.step == 4 && $scope.data.projects && $scope.data.projects != null) ||
						($scope.step == 6 && $scope.data.iqn_hosts && $scope.data.iqn_hosts != null)
					) {
						//Stop interval loop
						$interval.cancel(loadingInterval);

						//Edit Volume ->  Complete Volume fields after ends each integration loading
						switch($scope.step){
							case 2:
								$scope.fillEditVolumeUsers();
								break;
							case 4:
								if($scope.data.projects){
									var project = $scope.data.projects.find(function (obj) {
										return obj.id == $scope.data.volume.project.sys_id;
									});

									if(project.name != undefined) $scope.data.volume.project.name = project.name;

								}
								break;
							case 6:
								$scope.fillEditVolumeHosts();
								break;
						}

						$scope.loading = false;
						$scope.loadingModal = false;
					}
				}, 1000);
			}

			//Configure Users Variable inside Volume when USERs step is done
			if (
				$scope.step > 2 &&
				$scope.data.volume.type != "file_server_nfs" &&
				$scope.data.volume.type != "block"
			) {
				var users = c.selectedUsers;
				var username;
				var vindex;
				for (var i in users) {
					try {
						username = users[i].username;
						vindex = c.find(c.data.users, "username", username);
						users[i].permission = c.data.users[vindex].permission;
						c.data.userPermission.write[username] = false;
					} catch (e) {
						users[i].permission = "";
					}
				}
				c.data.volume.users = users;
			}

			//Configure Hosts Variable inside Volume when HOSTs step is done
			if (
				$scope.step > 6 &&
				($scope.data.volume.type == "block" ||
				 $scope.data.volume.type == "file_server_nfs")
			) {
				var hosts = c.selectedHosts;
				if (hosts) {
					c.data.volume.hosts = hosts;
				}

				var selectedHosts = c.data.selectedHosts;
				if (selectedHosts) {
					var host_obj;
					for (var host in selectedHosts) {
						host_obj = selectedHosts[host];
						var selected_ips = [];
						var selected_ips_id = [];
						var v_host_index = c.find(c.data.volume.hosts, "id", host);

						for (var ip_id in host_obj.selectedIps) {
							if (host_obj.selectedIps[ip_id] && v_host_index) {
								var v_ip_list_index = c.find(
									c.data.volume.hosts[v_host_index].ip_list,
									"id",
									ip_id
								);
								c.data.volume.hosts[v_host_index].ip_list[
									v_ip_list_index
								].selected = true;
								selected_ips_id.push(ip_id + "");
								selected_ips.push(
									c.data.volume.hosts[v_host_index].ip_list[v_ip_list_index]
									.display_value + ""
								);
							}
						}
						if (selected_ips_id && v_host_index) {
							c.data.volume.hosts[
								v_host_index
							].selected_ips_id = selected_ips_id;
							c.data.volume.hosts[v_host_index].selected_ips = selected_ips;
							var s_host_index = c.find(c.selectedHosts, "id", host);
							c.selectedHosts[s_host_index].selected_ips = selected_ips;
						}
					}
				}  
			}
		}
	};

	$scope.previousStep = function () {
		if ($scope.step > 1) {
			if (
				$scope.step == 3 &&
				($scope.data.volume.type == "file_server_nfs" ||
				 $scope.data.volume.type == "block")
			) {
				$scope.step = $scope.step - 2;
			} else if (
				$scope.step == 7 &&
				$scope.data.volume.type != "file_server_nfs" &&
				$scope.data.volume.type != "block"
			) {
				$scope.step = $scope.step - 2;
			} else {
				$scope.step--;
			}
		}
	};

	function validHosts(hosts) {
		if ($scope.step != 7 && $scope.data.volume.type == "block") {
			for (var i in hosts) {
				var iqn = hosts[i].iqn + "";
				if (!iqn || iqn == "" || iqn == "undefined") {
					return false;
				}
			}
		}
		if($scope.step == 7 && $scope.data.volume.type == "file_server_nfs") {
			for (var j in hosts) {
				if (hosts[j].ip_list.length == 0) {
					return false;
					//add edgar
				} else if(hosts[j].selected_ips_id == undefined || hosts[j].selected_ips_id == null ) {
					return false;

				} else if((hosts[j].selected_ips.length == 0 && hosts[j].selected_ips_id.length == 0)) {
					return false;
				}
			}
		}
		return true;
	}

	$scope.isStepValid = function () {
		switch ($scope.step) {
			case 1: //TYPE
				return $scope.data.volume.type;
			case 2: //USERS
				return c.selectedUsers.length != 0;
			case 3: //SIZE
				return $scope.data.step3_form.$valid && $scope.data.volume.size > 0 && $scope.data.volume.size_measurement && !$scope.maxAllowedFlag && !$scope.maxAllowedFlagTB;
			case 4: //PROJECT
				return $scope.data.step4_form.$valid;
			case 5: //NAME
				return $scope.data.step5_form.$valid;
			case 6: //Hosts
				return c.selectedHosts.length != 0 && validHosts(c.selectedHosts);
			case 7: //Confirmation
				return $scope.data.volume.length != 0 && validHosts(c.selectedHosts);
		}
		return false;
	};

	$scope.prepareWizard = function () {
		$scope.data.modal_title = "";

		// Select volume type
		if ($scope.data.volume.type) {
			var modal_title = "";
			if ($scope.editVolume) {
				modal_title = $scope.data.volume.name;
			}
			$scope.selectVolumeType($scope.data.volume.type, modal_title);
		}

		// Wizard Step
		$scope.step = 1;

		// Error count
		$scope.applyErrorCount = 0;
		$scope.modalErrorCount = 0;

		// Display New Project Form
		$scope.data.addNewProject = false;

		// Clear host lists
		$scope.data.selectedHosts = "";

		// Clear ips lists
		$scope.data.selectedIps = "";

		// Reload Project Field
		$rootScope.$broadcast("reloadProjectSelector");

		// Reset Validations
		$scope.data.step3_form.volume_size.$setPristine(true);
		$scope.data.step5_form.volume_name.$setPristine(true);

		// Reset IP Selector
		$scope.data.ip = {
			permission: "read"
		};

	};

	$scope.apply = function () {
		$scope.loading = true;

		if ($scope.data.addNewProject) {
			createProject();

			var createProjectInterval = $interval(function () {
				if ($scope.data.createProject != null) {
					$interval.cancel(createProjectInterval);
					createVolume();
				} else {
					return;
				}
			}, 1000);
		} else {
			createVolume();
		}
	};

	// Look for response on the queue, related to the getProjects request
	function getProjectsResult() {
		runningIntegration = true;
		$scope.server
			.get({
			action: "getProjectsResult",
			ms_queue_project_sys_id: $scope.data.ms_queue_project_sys_id,
			ibx: $rootScope.selectedIbx,
			volume: $scope.data.volume,
			editVolume: $scope.editVolume
		})
			.then(function (response) {
			$scope.data.projects = response.data.projects;
			if (response.data.volume && response.data.volume.project.name) {
				$scope.data.volume = response.data.volume;
			}
			$scope.loading = false;
		});
		runningIntegration = false;
	}

	// Look for response on the queue, related to the getUsers request
	function getUsersResult() {
		$scope.server.get({
			action: "getUsersResult",
			ms_queue_users_sys_id: $scope.data.ms_queue_users_sys_id
		}).then(function (response) {
			$scope.data.users = response.data.users;
			if ($scope.data.users) {
				$scope.loading = false;
			}
		});
	}

	// Look for response on the queue, related to the geCustomerMetrics request
	function getCustomerMetricsResult() {
		$scope.server
			.get({
			action: "getCustomerMetricsResult",
			volume: $scope.data.volume,
			ibx: $rootScope.selectedIbx,
			ms_queue_metrics_sys_id: $scope.data.ms_queue_metrics_sys_id
		})
			.then(function (response) {
			if (response.data.customerMetrics) {
				$scope.data.volume = response.data.volume;
				$scope.data.customerMetrics = response.data.customerMetrics;
				if ($scope.data.volume)
					$scope.data.volume.customerMetrics = response.data.customerMetrics;
				$scope.data.onDemandActive = response.data.onDemandActive;

				// Load Volume Sizes
				if ($scope.data.customerMetrics) {

					if($scope.editVolume != null){
						if($scope.editVolume.size_unit == 'Tb' ){
							$scope.data.max_allowed = $scope.maxAllowed / 1000;
							$scope.data.customerMetrics.total_allocated = $scope.data.customerMetrics.total_allocated / 1000;
							$scope.data.customerMetrics.total_quota     = $scope.data.customerMetrics.total_quota / 1000;
							$scope.data.loadingTB = false;
							$scope.data.loadingGB = true;
							$scope.noTriggerMeasurementTB = false;
							$scope.data.volume.size_measurement = 'tb';
						}else if($scope.editVolume.size_unit == 'Gb' ){
							$scope.data.loadingTB = true;
							$scope.data.loadingGB = false;
							$scope.noTriggerMeasurementGB = false;
							$scope.data.volume.size_measurement = 'gb';
						}
					}

					$scope.data.volume.customerMetrics = $scope.data.customerMetrics;

					$scope.data.volume.used_size =	$scope.data.customerMetrics.total_allocated;
					$scope.data.volume.available_size =	$scope.data.customerMetrics.total_quota - $scope.data.customerMetrics.total_allocated;
					$scope.data.volume.total_size =	$scope.data.customerMetrics.total_quota;
					$scope.data.volume.max_size = $scope.data.volume.available_size;

					if ($scope.editVolume) {
						$scope.data.volume.max_size = $scope.data.volume.available_size + $scope.editVolume.size;
						$scope.data.volume.used_size = $scope.data.customerMetrics.total_allocated - $scope.editVolume.size;
					}
				}

				$scope.loading = false;
			}
		});
	}

	// Look for response on the queue, related to the getProjects request
	function getVolumeResult() {
		$scope.server.get({
			action: "getVolumeResult",
			ms_queue_edit_volume_sys_id: $scope.data.ms_queue_edit_volume_sys_id
		}).then(function (response) {
			$scope.data.editVolumeData = response.data.editVolumeData;

			$scope.loading = false;
			if($scope.data.editVolumeData) {

				$scope.load();
			}
		});
	}

	// Init record watcher to listen changes on the queue, used to get request results
	function initRecordWatcher(callback, value) {
		$scope.data[value] = null;
		var interval = $interval(function () {
			if(runningIntegration)
				return;
			if ($scope.data[value]) {
				$interval.cancel(interval);
			} else if (!runningIntegration) {
				callback();
			}
		}, 1000);
	}

	$scope.fillEditVolumeHosts = function(){
		var edit = $scope.data.editVolumeData;
		if (edit) {
			var type = (
				$scope.data.editVolumeData.volume.share.type + "").toLowerCase();
			var hosts;
			switch (type) {
				case "block":
					hosts = $scope.data.editVolumeData.volume.hosts;
					break;
				case "iscsi":
					hosts = $scope.data.editVolumeData.volume.hosts;
					break;
				case "nfs":
					hosts = $scope.data.editVolumeData.volume.hosts;
					break;
				default:
					return;
			}

			var host_list = [];
			if (hosts) {
				for (var i in hosts) {
					host_list.push(hosts[i].id.replace(/-/g, ""));
				}

				$timeout(function () {
					$("#select-hosts").select2("val", host_list);
					c.hostChanged();
					if(type == "nfs") {
						$timeout(function() {
							for(var i in c.selectedHosts) {
								var host = c.selectedHosts[i];
								var ips = $scope.data.editVolumeData.authorized_ips;
								for(var k in ips) {
									for(var l in host.ip_list) {
										//if(host.ip_list[l].display_value == ips[k].split("/")[0] && host.ip_list[l].subnet.cidr == ips[k].split("/")[1]) {
										if(host.ip_list[l].display_value == ips[k].split("/")[0] && c.data.selectedHosts[host.id] != undefined ) {
											c.data.selectedHosts[host.id].selectedIps[host.ip_list[l].id] = true;
										}
									}
								}
							}

							/*for(var i in c.selectedHosts) {
								var host = c.selectedHosts[i];
								console.log("edgarline 808  host " + JSON.stringify(host));
								//var ips = $scope.data.editVolumeData.authorized_ips;
								var ips = host.ip_list
								console.log("edgarline 810  ips " + JSON.stringify(ips));
								for(var k in ips) {
									if(host.ip_address == ips[k].display_value){
										console.log("edgar entrou 814")
										$scope.data.selectedHosts[host.id].selectedIps[ips[k].id] = true;
									}

								}
							}*/
						}, 300);


					}
				}, 100);

			}
		}
	};

	$scope.fillEditVolumeUsers = function(){
		var edit = $scope.data.editVolumeData;
		if (edit) {
			var type = (edit.volume.share.type + "").toLowerCase();
			var users;
			var lun_id = edit.lun_id;
			if (lun_id && lun_id != "") {
				$scope.editVolume.lun_id = lun_id;
			}
			switch (type) {
				case "bucket":
					users = edit.bucket_users;
					break;
				case "smb":
					users = edit.smb_users;
					break;
				default:
					return;
			}

			var user_list = [];
			if (users) {
				for (var i in users) {
					user_list.push(users[i].user + "");
				}

				$("#select-users").select2("val", user_list);
				c.changed();

				//Load User Permissions
				var selectedUsers = c.selectedUsers;
				var username;
				var id;
				var vindex;
				var zindex;

				if(!c.data.userPermission){

					c.data.userPermission = {};
					c.data.userPermission.write = [];
				}

				for (var i in selectedUsers) {
					try {
						username = selectedUsers[i].username;
						c.data.userPermission.write[username] = false;
						id = selectedUsers[i].id;
						vindex = c.find(c.data.users, "username", username);
						zindex = c.find(users, "user", id);
						c.data.users[vindex].permission = users[zindex].permissions;
						var permission = users[zindex].permissions + '';
						permission = permission.toLowerCase();
						if (users[zindex].permissions && permission.indexOf('w') != -1 && permission.indexOf('r') != -1) {
							c.data.userPermission.write[username] = true;
						} else {
							c.data.userPermission.write[username] = false;
						}
					} catch (e) {

					}
				}
			}
		}
	};

	// Event Listener to trigger the Create Volume Modal
	$rootScope.$on("createEditVolume", function (event, obj) {
		//Loading
		$scope.loadingModal = true;
		$scope.loading = true;

		// Reset error count
		$scope.applyErrorCount = 0;
		$scope.data.errorMessage = '';

		// Reset primary variables
		$scope.editVolume = null;
		$scope.data.editVolumeData = null;
		$scope.data.volume = null;
		$scope.data.users = null;

		// Reset integration selectors
		c.selectedUser = null;
		c.selectedHost = null;
		$("#select-users").select2("data", null);
		$("#select-hosts").select2("data", null);
		c.changed();
		c.hostChanged();

		//Open Create/Edit Volume modal
		$("#create-volume").modal("show");

		if (obj) {
			//Edit Volume Section
			$scope.data.volume = {};
			$scope.data.title = "${Edit Volume}";
			var type = obj.share.type + "";
			$scope.editVolume = obj;
			$scope.vrCreateVolume = false;

			// Ask for selected volume data to the queue
			$scope.server.get({
				action: "getVolume",
				editVolume: obj
			}).then(function (response){
				$scope.data.ms_queue_edit_volume_sys_id = response.data.ms_queue_edit_volume_sys_id;
				initRecordWatcher(getVolumeResult, "editVolumeData");
			});
		} else {
			//Create Volume Section
			$scope.data.title = "${Create Volume}";
			$scope.editVolume = null;
			$scope.editVolumeData = null;
			$scope.data.volume = {};
			$scope.data.volume.max_allowed = $scope.maxAllowed;
			$scope.data.volume.size_measurement = "gb";
			$scope.data.measurement = 'GB';
			c.selectedUsers = [];
			c.selectedUsersAux = [];
			c.selectedHosts = [];
			c.selectedHostsAux = [];
			$scope.vrCreateVolume = true;
			$scope.data.loadingGB = false;
			$scope.data.loadingTB = false;
			$scope.noTriggerMeasurementTB = true;
			$scope.noTriggerMeasurementGB = true;
			$scope.msg_lunID = false;

			$scope.load();
		}

	});

	$scope.load = function(){
		var lun_id = "";
		if($scope.data.editVolumeData != null){
			lun_id =	$scope.data.editVolumeData.lun_id;
			$scope.msg_lunID = true;
		}
		$scope.server.get({
			action: "load",
			projects: $scope.data.projects,
			volume: $scope.editVolume,
			lun_id: lun_id,
			ibx: $rootScope.selectedIbx
		}).then(function (response) {
			// Set skip measurement
			//response.data.volume.skipMeasurement = true;
			// Fill volume type list
			$scope.data.volume_type_list = response.data.volume_type_list;
			// Get volume data
			$scope.data.volume = response.data.volume;
			// Get hosts select options
			$scope.data.host_select_options = response.data.host_select_options;
			// Get project list
			$scope.data.project_list = response.data.project_list;
			// Get hosts list
			$scope.data.hosts_list = response.data.hosts_list;
			// Get ips list
			$scope.data.ips_list = response.data.ips_list;

			$scope.data.measurement = (response.data.volume.size_measurement).toUpperCase();

			// Prepare wizard
			$scope.prepareWizard();

			if ($scope.editVolume) {
				//Go to 1st step of given type and wait the integration loading
				$scope.nextStep();
			} else {
				//Type screen is ready to create a new volume
				$scope.loading = false;
				$scope.loadingModal = false;
			}
		});

	};


	// Listening for form validation
	$rootScope.$on("hostFormValid", function (event, valid) {
		$scope.addNewHostValid = valid;
	});

	$scope.showNewProjectForm = function () {
		// Clear project selector
		$scope.data.volume.project = {};

		// Clear CI Field
		$rootScope.$broadcast("reloadProjectSelector");

		$scope.data.addNewProject = true;
	};

	// Validate volume name, check it it is unique
	$scope.validateVolumeName = function () {
		$scope.loading = true;
		$scope.server
			.get({
			action: "validateName",
			name: $scope.data.volume.name
		})
			.then(function (response) {
			$scope.loading = false;
			if (response.data.result) {
				$scope.data.step5_form.volume_name.$setValidity("unique", true);
			} else {
				$scope.data.step5_form.volume_name.$setValidity("unique", false);
			}
		});
	};

	function getSaveVolumeResult() {
		$scope.server
			.get({
			action: "getSaveVolumeResult",
			volume: $scope.data.volume,
			ms_queue_new_volume_sys_id: $scope.data.ms_queue_new_volume_sys_id,
			ibx: $rootScope.selectedIbx
		})
			.then(function (response) {
			$scope.data.saveVolume = response.data.saveVolume;
			if (response.data.saveVolume) {
				if (response.data.saveVolume.success == "true") {
					$scope.step = 8;
					$rootScope.$broadcast("reloadVolumesList");
					$rootScope.$broadcast("reloadProjectList");
					$scope.loading = false;
				} else {
					// Sum first try on error count
					$scope.applyErrorCount += 1;
					// stop loading
					$scope.loading = false;
					$scope.msgErroEAR = response.data.dataVolumeMsg;
				}
			}
		});
	}

	// Init error count
	$scope.applyErrorCount = 0;

	function createVolume() {
		// Retry function
		$scope.applyRetry = createVolume;

		$scope.loading = true; // start loading
		$scope.server
			.get({
			action: "save",
			ibx: $rootScope.selectedIbx,
			volume: $scope.data.volume,
			editVolume: $scope.editVolume
		})
			.then(function (res) {
			$scope.data.ms_queue_new_volume_sys_id = res.data.result;
			if ($scope.data.ms_queue_new_volume_sys_id) {
				// Reset error count
				$scope.applyErrorCount = 0;
				// Go to Success step
				$scope.step = 7;
				// Wait for queue response
				initRecordWatcher(getSaveVolumeResult, "saveVolume");
				//$scope.loading = false;
			} else {
				// Sum first try on error count
				$scope.applyErrorCount += 1;
				// stop loading
				$scope.loading = false;
			}
		});
	}

	function createProject() {
		$scope.loading = true;
		$scope.server
			.get({
			action: "createProject",
			ibx: $rootScope.selectedIbx,
			project_name: $scope.data.volume.project.name,
			project_description: $scope.data.volume.project.description
		})
			.then(function (response) {
			$scope.data.ms_queue_new_project_sys_id =
				response.data.ms_queue_new_project_sys_id;
			initRecordWatcher(getCreateProjectResult, "createProject");
		});
	}

	function getCreateProjectResult() {
		runningIntegration = true;
		$scope.server
			.get({
			action: "getCreateProjectResult",
			ms_queue_new_project_sys_id: $scope.data.ms_queue_new_project_sys_id,
			ibx: $rootScope.selectedIbx
		})
			.then(function (response) {
			$scope.data.createProject = response.data.createProject;
			if (response.data.createProject) {
				$scope.data.volume.project = {};
				$scope.data.volume.project.name = $scope.data.createProject.name;
				$scope.data.volume.project.sys_id = $scope.data.createProject.id;
			}
		});
		runningIntegration = false;
	}
}

sp_widget.css:
.loading-data {
  height: 100%;
  width: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  height: 540px;
}
.panel {
  min-height: 469px;
}
.error {
  color: red;
  margin-left: 15px;
}

form .tab-pane,
form.tab-pane {
  margin-top: 18px;
  padding-top: 10px;
  border-top: 1px solid #ddd;
}

.nav.nav-tabs li {
  width: auto !important;
}

.panel-body {
  overflow: initial;
  padding: 0px;
}

.btn-danger {
  margin-right: 5px;
}

.modal-body {
  .step-indicator {
    margin: auto;
    margin-top: 10px;
    width: 10px;
    height: 10px;
    display: flex;
    align-items: center;
    background: #cbd0d8;
    border-radius: 50%;
    z-index: 2;

    &.active {
      background: $info;
    }

    &:before {
      content: "";
      width: 50%;
      height: 2px;
      display: block;
      left: -5px;
      background: #cbd0d8;
      position: absolute;
      z-index: 1;
    }

    &:after {
      content: "";
      width: 50%;
      height: 2px;
      display: block;
      right: -5px;
      background: #cbd0d8;
      position: absolute;
      z-index: 1;
    }
  }

  .steps {
    padding: 30px 30px 20px 30px;
    margin-top: -15px;
    margin-left: -15px;
    margin-right: -15px;
    background: #f4f6f8;
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-semibold);

    ul {
      margin-bottom: 0;
      padding-left: 0;
      list-style: none;

      li {
        width: 16.3%; /*width: 19.6%;*/
        display: inline-block;
        position: relative;
        text-align: center;

        &:first-of-type .step-indicator:before {
          display: none;
        }

        &:last-of-type .step-indicator:after {
          display: none;
        }
      }
    }
  }

  @media screen and (min-width: 992px) {
    .separator {
      border-left: 1px solid #cbd0d8;
    }
  }
}

.modal .modal-dialog.modal-lg {
  @media screen and (min-width: 992px) {
    width: 700px;
  }
}

#create-volume {
  .modal-dialog {
    @media screen and (min-width: 992px) {
      width: 900px;
    }
  }
}

.select-option-caret {
  float: right;
  top: 10px;
  position: relative;
}

.min-height {
  padding-bottom: 80px !important;
}

.h5 {
  font-size: 16px;
}

.width-100 {
  width: 100%;
}

.step-2.active:before,
.step-3.active:before,
.step-4.active:before,
.step-5.active:before,
.step-6.active:before,
.step-7.active:before {
  width: 100%;
  left: -50%;
  background: $info;
}

.radiobox {
  margin-bottom: 10px;
  .radiobox-label {
    top: 0px;
  }
}

.volume-options {
  margin-top: 0px;
  margin-bottom: 5px;
}

.volume-options__option {
  label {
    margin: 0px 0;
    padding: 30px 30px;
    width: 100%;
    display: flex;
    align-items: center;
    border: 1px solid #e5e5e5;
    line-height: 1.3;

    > span {
      width: 100%;
      color: $info;
      font-size: 16px;
    }

    small {
      font-size: 12px;
      min-height: 15px;
    }
  }

  &.active > label,
  label:hover {
    background-color: $info;
    border-color: $info;

    span,
    .text-muted {
      color: #fff;
    }
  }
  display: inline-block;
  display: inline-block;
  width: calc(100% / 4 - 8px);
  margin-right: 4px;
  margin-left: 4px;
  margin-bottom: 8px;
}

.min-height {
  min-height: 400px !important;
  padding-bottom: 0px !important;
}

.no-worries span {
  margin-bottom: 40px;
}

.no-margin-bottom {
  margin-bottom: 0px;
}

.icon-check-eqx-icon {
  margin-top: 50px;
  display: block;
  color: #58ad25;
  font-size: 36px;
}

.step-title {
  margin-top: 20px;
  /*margin-bottom: 20px;*/
  display: block;
  font-size: 16px;
}

.step-title.file-server {
  margin-bottom: 5px;
}
.activation-step .step-title {
  font-size: 18px;
  /*margin-top: 50px;*/
}

.activation-step p {
  font-size: 12px;
  font-weight: 100;
  color: #adadad;
}

.activation-step .progress-message {
  max-width: 380px;
  margin: auto;
  padding: 20px;
  background-color: #f9f9f9;
  color: #000;
  font-size: 12px;
  /*margin-bottom: 70px;*/
}

.activation-step {
  a {
    display: block;
    margin-top: 5px;
  }
  .btn {
    margin-top: 20px;
    margin-bottom: 20px;
  }
}

.pointer {
  cursor: pointer;
}

/* All Step */
.form-group label > span {
  color: red !important;
}

/* Step 3 */
.step3_form .form-group {
  width: 120px;
  display: inline-block;
}

.step3_form .form-group input {
  text-align: right;
}

.step3_form .form-group label {
  width: 120px;
  margin-bottom: 0px;
}

.measurement {
  // width: 90px;
  display: inline;
  font-size: 12px;
  .btn-filter {
    padding: 7px 2px !important;
    text-align: center;
    font-size: 10px !important;
    font-weight: 600 !important;
    width: 50px;
    height: 30px;
    display: inline-block;
    margin-right: -4px !important;
  }
}

/* Step 4*/

.panel.new-project-panel {
  background: #f5f6f8;
  min-height: 100px;
  display: inline-block;
  width: 100%;
}

.panel.new-project-panel input {
  width: 50%;
}

.panel.new-project-panel textarea {
  width: 70%;
  height: 110px !important;
}

.new-project-title {
  margin-top: 20px;
  margin-bottom: 10px;
  display: block;
  font-size: 16px;
}

.protocol input[type="radio"] {
  position: relative;
  display: inline-block;
  width: 20px;
  height: 20px !important;
  margin-right: 5px;
  margin-left: 5px;
}
.protocol .protocol-label {
  position: relative;
  display: inline-block;
  height: 20px !important;
  line-height: 20px;
  vertical-align: super;
}

/* Step 5*/
.step5_form input[name="volume_name"] {
  width: 45%;
}
.step5_form input[name="volume_lun_id"] {
  width: 45%;
}

.step5_form .SumoSelect > .optWrapper > .options {
  border-radius: 2px;
  position: relative;
  max-height: 160px;
}

.input-group-addon {
  padding: 6px 12px;
  font-size: 14px;
  font-weight: normal;
  line-height: 1;
  color: #595a5d;
  text-align: center;
  background-color: #fff;
  border: 1px solid #ccc;
  border-radius: 4px;
}

.panel.new-host {
  min-height: 0px;
  background: #f6f6f6;
  padding-bottom: 30px;
}

.form-group-ip {
  display: inline-block;
  margin-right: 20px;
}

.form-group-ip .SumoSelect {
  width: 280px;
}

.form-group-ip label.btn {
  margin-right: 10px;
  border-radius: 0px !important;
}

.form-group-ip label.btn.btn-primary.active {
  color: #fff;
  background-color: #00a0e4;
  border: 1px solid #008ecb !important;
}

.form-group-ip label.btn.btn-primary {
  color: #737373;
  background-color: #ffffff;
  border: 1px solid #737373 !important ;
  box-shadow: none;
}

.users {
  th {
    font-size: larger;
  }
  td {
    font-size: small;
  }
  table {
    margin-top: 15px;
  }
}

.filters {
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  > span {
    position: relative;
    font-size: 15px;
    font-family: var(--eq-font-family);
    font-weight: var(--eq-font-weight-light);
  }
  .filters-badge {
    margin-left: 4px;
    width: 22px;
    height: 22px;
    display: inline-flex;
    justify-content: center;
    align-items: center;
    background: $info;
    border-radius: 50%;
    color: #fff;
    font-size: 12px;
    line-height: 1;
    //text-indent: -1px;
  }
  .filter-plus {
    margin-left: 20px;
    margin-right: 4px;
    vertical-align: middle;
    font-size: 26px;
    font-weight: 900;
    font-family: var(--eq-font-family);
  }
  .filter-border {
    border: 1px solid #a9b2bd;
    border-radius: 3px;
    padding: 2px;
    padding-left: 6px;
    display: flex;
    align-items: center;
  }
  .filter-row {
    margin-left: 0px;
    width: 100% !important;
  }
  .filter-row.no-border {
    margin-bottom: 0;
    border-bottom: 0;
  }

  .filter-row > .row-dropdowns {
    margin-left: -4px;
    margin-right: -4px;
    > .col-md-4,
    > .col-md-6 {
      padding: 0 4px;
    }
  }
  .filter-row > .row > .col-md-12,
  .filter-row > .row > .col-md-6 {
    margin-left: -4px;
    margin-right: -4px;
    display: flex;
    input[type="checkbox"] {
      display: none;
    }
    label.button {
      margin: 0 4px;
      padding: 6px 8px;
      border: 1px solid #ddd;
      color: #404040;
      white-space: nowrap;
      cursor: pointer;
      font-size: 12px;
    }
    label.button:hover {
      border-color: $info;
    }
    input[type="checkbox"]:checked + label.button {
      background: #6c6c6c;
      border-color: #6c6c6c;
      color: #fff;
    }
  }
  .filter-buttons {
    a {
      margin-right: 24px;
    }
  }
}
.filter-row .light {
  background: #ebebeb;
  padding: 10px 10px;
  display: block;
  margin-bottom: 20px;
  margin-top: 20px;
  border: 1px solid #dedede;
}
.filter-row .no-margin-top {
  margin-top: 0px !important;
}
.filter-options.filter-buttons label {
  margin: 0px !important;
  margin-right: 4px !important;
}
.filter-row .title {
  min-width: 510px;
}
.filter-row .form-group {
  margin-bottom: 0px;
}
.filter-row .filter-buttons .light {
  background: #fff;
}
.onoffswitch-switch {
  display: block;
  position: absolute;
  top: 0;
  margin-top: 6px;
}
.replicate-eti-question-answered {
  display: block;
  margin-left: 80px;
  margin-top: -22px;
}

.field-label {
  font-size: medium;
}

.progress {
  height: 10px !important;
  width: 40%;
  min-width: 123px;
  margin-bottom: 0;

  .progress-bar-info {
    background-color: $info;
  }
}
#btnCancel, #btnBack {
  background: transparent;
  border: 1px solid #009AFF !important;
}

#boxError {
  height: 82px;
  background: #f2f2f2;
  width: 60%;
  margin-left: 20%;

}

sp_widget.script:
(function () {
	/* populate the 'data' object */
	var result = null;
	var default_project_name = "Default project";
	data.title = "Create Volume";

	// Get user account
	var customerPermission = new EQIX_Customer_Permissions();
	var account_id = customerPermission.getActiveAccountSysId();

	data.account_id = account_id;

	var subnets = [];
	var grSubnet = new GlideRecord('u_subnet');
	grSubnet.addEncodedQuery('u_account=' + data.account_id + '^u_active_flag=true');
	grSubnet.query();
	while(grSubnet.next()){
		var obj = {};
		obj.id = grSubnet.getValue('sys_id');
		obj.ip = grSubnet.getValue('ip_address');
		obj.mask = grSubnet.getValue('u_mask');
		obj.cidr = grSubnet.getValue("u_splitted_cidr") || grSubnet.u_ip_network.u_cidr.getValue();
		subnets.push(obj);
	}
	data.subnets = subnets;
	var size_measurement = '';
	function convertTo(value, from, to, att) {
		var result = 0;

		if (value == 0 || value < 0.0) return result;

		if (from == "gb" && to == "gb" ){
			result = value;
		} 

		if (from == "tb" && to == "gb"   ){
			result = value * 1000;
		} 

		if (from == "gb" && to == "tb"  ){
			result = value / 1000;
		} 

		return result;
	}

	// Load hosts list
	function loadHostList(iqn_hosts) {
		var hosts_list = [];

		var getHosts = new GlideRecord("cmdb_ci");
		getHosts.addEncodedQuery(gs.getProperty("EQIX_IDATA_Filter.Server_Classes") + "^install_status=1^u_account=" + account_id + "^NQ" + gs.getProperty("EQIX_IDATA_Filter.Server_Classes_Custom") + "^install_status=1^u_account=" + account_id);
		getHosts.orderBy("u_portal_display_name");
		getHosts.query();

		while (getHosts.next()) {
			var obj = {};
			obj.id = getHosts.getValue("sys_id");
			obj.iqn = '';
			for(var i in iqn_hosts){
				var iqn_hosts_id = iqn_hosts[i].id;
				iqn_hosts_id = iqn_hosts_id.toString().replaceAll('-','');
				if(iqn_hosts_id == obj.id){
					if (iqn_hosts[i].iqns[0])
						obj.iqn = iqn_hosts[i].iqns[0];
					break;
				}
			}
			//var iqn_table = "ref_" + getHosts.sys_class_name;
			//obj.iqn = getHosts[iqn_table].u_iqn + "";
			obj.display_value = getHosts.getValue("u_portal_display_name");
			obj.ip_address = getHosts.getValue("ip_address");
			obj.ip_list = loadIpList(obj.id + "");
			hosts_list.push(obj);
		}
		data.hosts_list = hosts_list;
		return;
	}

	// Load IPs list
	function loadIpList(host_ci) {
		var ips_list = [];

		var getIps = GlideRecord("cmdb_rel_ci");
		//getIps.addEncodedQuery("child.sys_class_name=cmdb_ci_ip_address^child.u_active_flag=true^child.ref_cmdb_ci_ip_address.u_subnetISNOTEMPTY");
		getIps.addEncodedQuery("child.sys_class_name=cmdb_ci_ip_address^child.u_active_flag=true");
		getIps.addQuery("parent", host_ci);
		getIps.query();
		while(getIps.next()) {
			var ipCI = new GlideRecordUtil().getCIGR(getIps.child.getValue());
			var obj = {};
			obj.id = ipCI.getUniqueValue();
			obj.display_value = ipCI.getValue("ip_address");
			obj.subnet = {
				id: ipCI.getValue("u_subnet"),
				cidr: ipCI.u_subnet.u_splitted_cidr.getValue(),
				ip: ipCI.u_subnet.ip_address.getValue(),
				mask: ipCI.u_subnet.u_mask.getValue()
			};
			ips_list.push(obj);
		}


		return ips_list;
	}

	// Load Volume list
	function loadProjectList() {
		data.ms_queue_project_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getProjects",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/projects?customer=" + account_id + "&site=" + input.ibx.ear_id,
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	function saveStorage(input) {
		if (input.volume.size_measurement == "gb") {
			input.volume.size_measurement = "Gb";
		}else {
			input.volume.size_measurement = "Tb";
		}

		try {
			var result;

			if (input.editVolume) {
				result = updateVolume(input);
			} else {
				result = createVolume(input);
			}
			return result;
		} catch (e) {
			gs.addErrorMessage(e);
			return false;
		}
	}

	/* Server Actions */
	if (input && input.action == "validateName") {
		data.result = new EQIX_ID_PortalUtils().validateVolumeName(
			input.name,
			account_id
		);
		return;
	}

	if (input && input.action == "getHostName") {
		data.result = new EQIX_ID_PortalUtils().getHostName(input.host);
		return;
	}

	if (input && input.action == "changeMeasurement") {

		var vol = input.volume;
		var from = input.from;
		var to = input.to;
		var total_quota = input.total_quota;
		var total_use = input.total_use;
		var available_size = input.available_size;
		var max_size = input.max_size;
		var max_allowed = input.max_allowed;


		if (from != to) {
			vol.available_size = convertTo(vol.available_size, from, to, available_size);
			vol.used_size = convertTo(vol.used_size, from, to, total_use);
			vol.total_size = convertTo(vol.total_size, from, to, total_quota);
			vol.max_size = convertTo(vol.max_size, from, to, max_size);
			vol.max_allowed = convertTo(vol.max_allowed, from, to, max_allowed);
		}
		data.volume = vol;
		return;
	}

	if (input && input.action == "save") {
		data.result = saveStorage(input);
		return;
	}

	if (input && input.action == "getIQNHosts"){
		data.ms_queue_hosts_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getHosts",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/hosts?customer=" + account_id + "&page_size=999",
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	if (input && input.action == "getIQNHostsResult") {
		result = getQueueResponse(input.ms_queue_hosts_sys_id);
		if (result == null) {
			return;
		}
		data.iqn_hosts = result;
		loadHostList(data.iqn_hosts.results);
		return;
	}

	if (input && input.action == "saveIqn") {
		var cmdb_ci = input.cmdb_ci;
		var iqn = input.iqn;

		//Insert save/edit IQN action in the queue
		data.ms_queue_save_iqn_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "saveIqn",
			service: "idata",
			priorization: "high",
			data: {
				url: "/api/hosts/" + cmdb_ci + "/",
				method: "PUT",
				payload: {
					iqns: [iqn]
				}
			}
		});
		// 		}
		return;
	}
	function getNameHosts(ip, account){

		var grCmdbRelCi = new GlideRecord('cmdb_rel_ci');
		grCmdbRelCi.addEncodedQuery("child.sys_id="+ip+"^child.u_account="+account);
		grCmdbRelCi.query();
		var list = [];
		while (grCmdbRelCi.next()) {
			list.push(grCmdbRelCi.getValue('parent'));
		}

		var getHostNames = new GlideRecord("cmdb_ci");
		getHostNames.addEncodedQuery("sys_idIN"+list.toString());
		getHostNames.query();
		var listHostName = [];
		while(getHostNames.next()){
			listHostName.push(getHostNames.getValue('u_hostname'));
		}
		return listHostName.toString();
	}

	if (input && input.action == "saveIp") {
		var host_id = input.host_id;
		var new_ip = input.new_ip;
		var new_ip_subnet = input.new_ip_subnet;
		var ip_sys_id;

		if (!host_id || !new_ip || new_ip == ''){
			return;
		}

		var grIPExists = new GlideRecord('cmdb_ci_ip_address');
		grIPExists.addQuery('ip_address', new_ip);
		grIPExists.addQuery('u_subnet', new_ip_subnet);
		grIPExists.addQuery('u_account', data.account_id);
		grIPExists.query();
		if (grIPExists.next()){
			//This IP Already Exists
			var active = grIPExists.u_active_flag;
			if (!active){
				//If it was inactive, just set Active = True
				ip_sys_id = grIPExists.getValue('sys_id');
				grIPExists.u_active_flag = true;
				grIPExists.u_subnet = new_ip_subnet;
				// 				if (grIPExists.nic.cmdb_ci != host_id){
				// 					var grNicUpdate = new GlideRecord('cmdb_ci_network_adapter');
				// 					if(grNicUpdate.get(grIPExists.getValue('nic'))){
				// 						grNicUpdate.cmdb_ci = host_id;
				// 						grNicUpdate.update();
				// 					} else {
				// 						//IP is inactive, but there is no NIC to associate new Host
				// 						data.errorMessage = 'IP Address ' + new_ip + ' is pre-allocated to another host';
				// 						return;
				// 					}
				// 				}

				grIPExists.setWorkflow(false);
				grIPExists.update();

				var grRelCI = new GlideRecord("cmdb_rel_ci");
				grRelCI.initialize();
				grRelCI.setValue("child", ip_sys_id);
				grRelCI.setValue("parent", host_id);
				grRelCI.setValue("type", "cb5592603751200032ff8c00dfbe5d17");
				grRelCI.insert();

				data.errorMessage = 'IP address ' + new_ip + ' was inactive and has been reactivated';
			} else {
				//Else, do not duplicate, abort action
				data.errorMessage = 'IP Address ' + new_ip + ' is already in use by another Host ('+getNameHosts(grIPExists.getValue('sys_id'),data.account_id)+')! Please review your Host List.';
				return;
			}
		} else {

			var grIp = new GlideRecord('cmdb_ci_ip_address');
			grIp.newRecord();
			grIp.ip_address = new_ip;
			//grIp.nic = nic_sys_id;
			grIp.u_subnet = new_ip_subnet;
			grIp.u_account = account_id;
			grIp.setWorkflow(false);
			ip_sys_id = grIp.insert();

			var grRelCI = new GlideRecord("cmdb_rel_ci");
			grRelCI.initialize();
			grRelCI.setValue("child", ip_sys_id);
			grRelCI.setValue("parent", host_id);
			grRelCI.setValue("type", "cb5592603751200032ff8c00dfbe5d17");
			grRelCI.insert();
		}

		var ip_obj = {};
		ip_obj.id = ip_sys_id;
		ip_obj.display_value = new_ip;
		ip_obj.subnet = {
			id: grIp.getValue("u_subnet"),
			cidr: grIp.u_subnet.u_splitted_cidr.getValue(),
			ip: grIp.u_subnet.ip_address.getValue(),
			mask: grIp.u_subnet.u_mask.getValue()
		};

		data.new_ip_obj = ip_obj;

		return;
	}

	if (input && input.action == "load") {
		// Get current volume
		if (input.volume && input.volume.id) {
			//Prepare Edit Modal

			data.volume = {};

			var type = (input.volume.share.type + "").toLowerCase();
			switch (type) {
				case "smb":
					data.volume.type = "file_server_smb";
					break;
				case "nfs":
					data.volume.type = "file_server_nfs";
					break;
				case "bucket":
					data.volume.type = "object";
					break;
				case "block":
					data.volume.type = "block";
					break;
				case "iscsi":
					data.volume.type = "block";
					break;
				default:
					data.volume.type = "file_server_smb";
					break;
			}

			//Load Volume Data
			data.volume.ips = input.volume.authorized_ips || [];
			data.volume.id = input.volume.id;
			data.volume.name = input.volume.label_name;
			//data.volume.hosts = "";
			data.volume.lun_id = input.lun_id;
			data.volume.project = {};
			data.volume.project.sys_id = input.volume.project;
			data.volume.total_size = 0; //Available if contracted OnDemand
			data.volume.available_size = 0; //Available to this volume
			data.volume.used_size = 0; //Previously used
			data.volume.size = input.volume.size; //Current volume size
			data.volume.size_measurement = input.volume.size_unit.toLowerCase();
			if (type == "smb" || type == "iscsi")
				data.volume.min_size = input.volume.size;
			else data.volume.min_size = 1;
			data.volume.max_size = 0;
			data.volume.max_allowed = 25000;
		} else if (input.volume) {
			data.volume = input.volume;
			if (!data.volume.project){
				data.volume.project = {};
				data.volume.project.sys_id = "";
			}
		} else {
			// new volume
			data.volume = {};
			data.volume.ips = [];
			data.volume.name = "";
			data.volume.hosts = "";
			data.volume.project = {};
			data.volume.project.sys_id = "";
			data.volume.total_size = 0; //Available if contracted OnDemand
			data.volume.available_size = 0; //Available to this volume
			data.volume.used_size = 0; //Previously used
			data.volume.size = 0; //Current volume size
			data.volume.min_size = 1;
			data.volume.max_size = 0;
			data.volume.max_allowed = 25000;
			data.volume.size_measurement = "gb"; // Set Default mensurement value
		}

		// Agent Types
		data.volume_type_list = [
			{
				id: "file_server_nfs",
				title: gs.getMessage("File Storage"),
				alt_title: gs.getMessage("NFS Share"),
				description: gs.getMessage("NFS Share")
			},
			{
				id: "file_server_smb",
				title: gs.getMessage("File Storage"),
				alt_title: gs.getMessage("SMB Share"),
				description: gs.getMessage("SMB Share")
			},
			{
				id: "block",
				title: gs.getMessage("Block Storage"),
				description: gs.getMessage("iSCSI Volume")
			},
			{
				id: "object",
				title: gs.getMessage("Object Storage"),
				description: "Bucket"
			}
		];

		data.hosts_list = [];
		data.ips_list = [];
		data.project_list = [];

		return;
	}

	function convert(size_measurement, volume_size){
		var result= {};
		if(size_measurement == 'tb'){
			result.volume_size = volume_size/1000;
			result.size_measurement = 'Tb';
		}else {
			result.volume_size = volume_size;
			result.size_measurement = 'Tb';
		}

		return result;
	}

	function createVolume(input) {
		var users = [];
		var hosts = [];
		var iqns = [];
		var obj = {};
		var lun_id;

		if (input.volume.lun_id) {
			lun_id = input.volume.lun_id;
		}

		//Get Users Object Array
		for (var i in input.volume.users) {
			obj = {};
			obj.user = input.volume.users[i].id;
			if(input.volume.users[i].permission){
				obj.permissions = input.volume.users[i].permission;
			}else{
				obj.permissions = 'r';
			}

			users.push(obj);
		}

		var ipList = [];
		//Get Host ID list

		for (var j in input.volume.hosts) {
			var host = input.volume.hosts[j].id + "";
			if (host && host != "" && host != "undefined") hosts.push(host);
			var iqn = input.volume.hosts[j].iqn + "";
			if (iqn && iqn != "" && iqn != "undefined") iqns.push(iqn);
			for(var k in input.volume.hosts[j].ip_list) {
				//if(input.volume.hosts[j].ip_list[k].selected && input.volume.hosts[j].ip_list[k].subnet.cidr)
				//ipList.push(input.volume.hosts[j].ip_list[k].display_value + "/" + input.volume.hosts[j].ip_list[k].subnet.cidr);
				if(input.volume.hosts[j].ip_list[k].selected)
					ipList.push(input.volume.hosts[j].ip_list[k].display_value);
			}
		}

		var type = input.volume.type + "";
		var action = "";
		var url = "";

		switch (type) {
			case "file_server_smb":
				action = "postSmbShare";
				url = "/api/smb-share/";
				break;
			case "file_server_nfs":
				action = "postNfsShare";
				url = "/api/nfs-share/";
				break;
			case "object":
				action = "postBuckets";
				url = "/api/buckets/";
				break;
			case "block":
				action = "postIscsiShare";
				url = "/api/iscsi-share/";
				break;
			default:
				return;
		}
		data.ms_queue_new_volume_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: action,
			service: "idata",
			priorization: "high",
			data: {
				url: url,
				method: "POST",
				payload: {
					volume: {
						name: input.volume.name,
						label_name: input.volume.name,
						size: input.volume.size,
						size_unit: input.volume.size_measurement ,
						readonly: false,
						project: input.volume.project.sys_id,
						customer: account_id,
						hosts: hosts,
						site: input.ibx.ear_id
					},
					smb_users: users,
					bucket_users: users,
					lun_id: lun_id,
					authorized_ips: ipList || [],
					authorized_networks: [],
					authorized_hostnames: [],
					archive: false
				}
			}
		});
		result = data.ms_queue_new_volume_sys_id;
		return result;
	}

	function updateVolume(input) {
		var users = [];
		var hosts = [];
		var iqns = [];
		var obj = {};
		var lun_id;

		if (input.volume.lun_id) {
			lun_id = input.volume.lun_id;
		}
		//Get Users Object Array
		for (var i in input.volume.users) {
			obj = {};
			obj.user = input.volume.users[i].id;
			if(input.volume.users[i].permission){
				obj.permissions = input.volume.users[i].permission;
			}else{
				obj.permissions = "r";

			}
			users.push(obj);
		}

		//Get Host ID list
		var ipList = [];
		for (var j in input.volume.hosts) {
			hosts.push(input.volume.hosts[j].id + "");
			var iqn = input.volume.hosts[j].iqn + "";
			if (iqn && iqn != "" && iqn != "undefined") iqns.push(iqn);
			for(var k in input.volume.hosts[j].ip_list) {
				//if(input.volume.hosts[j].ip_list[k].selected && input.volume.hosts[j].ip_list[k].subnet.cidr)
				//ipList.push(input.volume.hosts[j].ip_list[k].display_value + "/" + input.volume.hosts[j].ip_list[k].subnet.cidr);
				if(input.volume.hosts[j].ip_list[k].selected)
					ipList.push(input.volume.hosts[j].ip_list[k].display_value );
			}
		}


		var type = input.volume.type + "";
		var action = "";
		var url = "";

		switch (type) {
			case "file_server_smb":
				action = "putSmbShare";
				url = "/api/smb-share/" + input.editVolume.share.id + "/";
				break;
			case "file_server_nfs":
				action = "putNfsShare";
				url = "/api/nfs-share/" + input.editVolume.share.id + "/";
				break;
			case "object":
				action = "putBuckets";
				url = "/api/buckets/" + input.editVolume.share.id + "/";
				break;
			case "block":
				action = "putIscsiShare";
				url = "/api/iscsi-share/" + input.editVolume.share.id + "/";
				break;
			default:
				return;
		}

		data.ms_queue_new_volume_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: action,
			service: "idata",
			priorization: "high",
			data: {
				url: url,
				method: "PUT",
				payload: {
					volume: {
						name: input.volume.name,
						label_name: input.volume.name,
						size: input.volume.size,
						//size_unit: "Gb",
						size_unit: input.volume.size_measurement,
						readonly: false,
						project: input.volume.project.sys_id,
						customer: account_id,
						hosts: hosts,
						site: input.ibx.ear_id
					},
					smb_users: users,
					bucket_users: users,
					lun_id: lun_id,
					authorized_ips: ipList || [],
					authorized_networks: [],
					authorized_hostnames: []
				}
			}
		});
		result = data.ms_queue_new_volume_sys_id;
		return result;
	}

	if (input && input.action == "getSaveVolumeResult") {
		result = getCompleteQueueResponse(input.ms_queue_new_volume_sys_id);
		if (result == null) {
			return;
		}
		data.saveVolume = result;
		return;
	}

	if (input && input.action == "createProject") {
		data.ms_queue_new_project_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "postProjects",
			service: "idata",
			priorization: "high",
			data: {
				url: "/api/projects/",
				method: "POST",
				payload: {
					name: input.project_name,
					description: input.project_description,
					customer: account_id,
					site: input.ibx.ear_id
				}
			}
		});
		return;
	}

	if (input && input.action == "getCreateProjectResult") {
		result = getQueueResponse(input.ms_queue_new_project_sys_id);
		if (result == null) {
			return;
		}
		data.createProject = result;
		return;
	}

	function selectDefaultProject(){
		//Load Default Project
		if (data.projects && data.volume) {
			var projects = data.projects;
			for (var i in projects) {
				var project = projects[i];
				//if (project.name == default_project_name) {
				try {
					data.volume.project = {};
					data.volume.project.name = project.name + "";
					data.volume.project.sys_id = project.id + "";
				} catch (e) {
					gs.addErrorMessage(e);
				}
				//}
			}
		}
	}

	if (input && input.action == "getProjects") {
		data.ms_queue_project_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getProjects",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/projects?customer=" + account_id + "&site=" + input.ibx.ear_id,
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	if (input && input.action == "getProjectsResult") {
		result = getQueueResponse(input.ms_queue_project_sys_id);
		if (result == null) {
			return;
		}
		data.projects = result;

		//Do not select Default Volume when current action is Edit Volume
		if (input.volume && !input.editVolume && data.projects && (!input.volume.project.sys_id || input.volume.project.sys_id == '')){
			data.volume = input.volume;
			selectDefaultProject();
		}

		return;
	}

	if (input && input.action == "getUsers") {
		data.ms_queue_users_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getLdapUser",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/ldap-user?customer=" + account_id + "&site=" + input.ibx.ear_id,
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	if (input && input.action == "getUsersResult") {
		result = getQueueResponse(input.ms_queue_users_sys_id);
		if (result == null) {
			return;
		}
		var listUserCreated = [];
		for(var x=0; x < result.length; x++){
			if(result[x].status == 'Created'){
				listUserCreated.push(result[x]);
			}
		}

		data.users = listUserCreated;
		//data.users = result;
		return;
	}

	if (input && input.action == "getVolume") {
		var id = input.editVolume.share.id;
		type = (input.editVolume.share.type + "").toLowerCase();
		var action = "";
		var url = "";

		switch (type) {
			case "smb":
				action = "getSmbShare";
				url = "api/smb-share/" + id + "/";
				break;
			case "nfs":
				action = "getNfsShare";
				url = "api/nfs-share/" + id + "/";
				break;
			case "bucket":
				action = "getBuckets";
				url = "api/buckets/" + id + "/";
				break;
			case "block":
				action = "getIscsiShare";
				url = "api/iscsi-share/" + id + "/";
				break;
			case "iscsi":
				action = "getIscsiShare";
				url = "api/iscsi-share/" + id + "/";
				break;
			default:
				return;
		}

		data.ms_queue_edit_volume_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: action,
			service: "idata",
			priorization: "high",
			data: {
				url: url,
				method: "GET"
			}
		});
		return;
	}

	if (input && input.action == "getVolumeResult") {
		result = getQueueResponse(input.ms_queue_edit_volume_sys_id);
		if (result == null) {
			return;
		}
		data.editVolumeData = result;
		return;
	}

	if (input && input.action == "getCustomerMetricsResult") {
		result = getQueueResponse(input.ms_queue_metrics_sys_id);
		if (result == null) {
			return;
		}

		data.volume = input.volume;
		data.customerMetrics = {};
		data.customerMetrics = result;

		data.onDemandActive = false;
		//Get if onDemand is active for the account, if it is, add the amount to the total_quota attribute on customer_metrics
		var mainIdataCi = new GlideRecord("u_intelligent_data_virtual_storage");
		mainIdataCi.addQuery("u_account", account_id);
		mainIdataCi.addQuery("location", input.ibx.sys_id);
		mainIdataCi.addQuery("u_active_flag", true);

		mainIdataCi.query();
		if (mainIdataCi.next()) {
			if (
				["activated", "deactivation_requested"].indexOf(
					mainIdataCi.u_on_demand_status.getValue()
				) > -1
			) {
				data.customerMetrics.total_quota += parseFloat(
					mainIdataCi.u_on_demand_size_limit.getValue()
				) * 1000;
				data.onDemandActive = true;
			}
		}

		if (data.volume) {
			data.volume.customerMetrics = {};
			data.volume.customerMetrics = data.customerMetrics;
			return;
		}
	}

	if (input && input.action == "getCustomerMetrics") {
		data.ms_queue_metrics_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getCustomerMetrics",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/customer-metrics/?customer=" +
				account_id +
				"&site=" +
				input.ibx.ear_id,
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	function loadCustomerMetrics() {
		data.ms_queue_metrics_sys_id = new EQIX_Message_Queue().create({
			region: "BR",
			action: "getCustomerMetrics",
			service: "idata",
			priorization: "high",
			data: {
				url:
				"/api/customer-metrics/?customer=" +
				account_id +
				"&site=" +
				input.ibx.ear_id,
				method: "GET",
				payload: {}
			}
		});
		return;
	}

	function getQueueResponse(sys_id) {
		var grUMsQueue = new GlideRecord("u_ms_queue");
		if (!grUMsQueue.get(sys_id)) {
			return null;
		}

		var result = grUMsQueue.getValue("u_response"); //u_response - u_data

		if (!result) {
			return null;
		}

		result = JSON.parse(result);

		if (!result.data) {
			return null;
		}
		result = GlideStringUtil.base64Decode(result.data);

		if (!result) {
			return null;
		}

		result = JSON.parse(result);
		postUserLogs(grUMsQueue);

		return result;
	}

	function postUserLogs(record) {
		var action = record.getValue("u_action");
		var editActions = [
			"putSmbShare",
			"putNfsShare",
			"putBuckets",
			"putIscsiShare"
		];
		var postActions = [
			"postNfsShare",
			"postSmbShare",
			"postIscsiShare",
			"postBuckets"
		];
		if (
			!action ||
			(action != "postProjects" &&
			 editActions.indexOf(action) == -1 &&
			 postActions.indexOf(action) == -1)
		) {
			return null;
		}
		var data = JSON.parse(GlideStringUtil.base64Decode(record.u_data));
		var message = "";
		var infos;
		var object;
		if (action == "postProjects") {
			message = "Project {0} was created";
			infos = {
				payload: {
					customer: data.payload.customer,
					site: input.ibx.ear_name
				}
			};
			object = data.payload.name;
		} else {
			if (editActions.indexOf(action) != -1) {
				message = "Volume {0} was edited";
			} else if (postActions.indexOf(action) != -1) {
				message = "Volume {0} was created";
			}
			infos = {
				payload: {
					customer: data.payload.volume.customer,
					site: input.ibx.ear_name
				}
			};
			object = data.payload.volume.name;
		}
		new EQIX_Intelligent_Data().postUserLogs(record, infos, message, object);
	}

	function getCompleteQueueResponse(sys_id) {
		var grUMsQueue = new GlideRecord("u_ms_queue");
		if (!grUMsQueue.get(sys_id)) {
			return null;
		}

		var result = grUMsQueue.getValue("u_response"); //u_response - u_data

		if (!result) {
			return null;
		}

		result = JSON.parse(result);
		data.dataVolumeMsg = JSON.parse(GlideStringUtil.base64Decode(result.data));
		if(result.success == "true")
			postUserLogs(grUMsQueue);

		return result;
	}
})();
